296	func CapabilitiesViaService(ctx context.Context, workDir, harnessName string) (*HarnessCapabilities, error) {
297		if ctx == nil {
298			ctx = context.Background()
299		}
300		svc, err := NewServiceFromWorkDir(workDir)
301		if err != nil {
302			return nil, fmt.Errorf("agent: build service: %w", err)
303		}
304		infos, err := svc.ListHarnesses(ctx)
305		if err != nil {
306			return nil, fmt.Errorf("agent: list harnesses: %w", err)
307		}
308		var info *agentlib.HarnessInfo
309		for i := range infos {
310			if infos[i].Name == harnessName {
311				info = &infos[i]
312				break
313			}
314		}
315		if info == nil {
316			return nil, fmt.Errorf("agent: unknown harness: %s", harnessName)
317		}
318	
319		// Pull binary and reasoning-level metadata from the local registry — the
320		// service does not expose these directly today.
321		registry := newHarnessRegistry()
322		harness, _ := registry.Get(harnessName)
323	
324		caps := &HarnessCapabilities{
325			Harness:             info.Name,
326			Available:           info.Available,
327			Binary:              harness.Binary,
328			Path:                info.Path,
329			Surface:             harness.Surface,
330			CostClass:           info.CostClass,
331			IsLocal:             info.IsLocal,
332			ExactPinSupport:     info.ExactPinSupport,
333			SupportsEffort:      len(info.SupportedReasoning) > 0 || harness.EffortFlag != "",
334			SupportsPermissions: len(info.SupportedPermissions) > 0 || len(harness.PermissionArgs) > 0,
335		}
336		if len(info.SupportedReasoning) > 0 {
337			caps.ReasoningLevels = append([]string{}, info.SupportedReasoning...)
338		} else if len(harness.ReasoningLevels) > 0 {
339			caps.ReasoningLevels = append([]string{}, harness.ReasoningLevels...)
340		}
341	
342		if harness.DefaultModel != "" {
343			caps.Model = harness.DefaultModel
344			caps.Models = []string{harness.DefaultModel}
345		}
346	
347		return caps, nil
348	}
